@AbapCatalog.viewEnhancementCategory: [#NONE] @AccessControl.authorizationCheck: #NOT_REQUIRED @EndUserText.label: 'Upload PO - Header (Intf.)' @VDM.viewType: #COMPOSITE define view entity ZEXED_I_UP_PDCMP_H as select from zexed_up_pdcmp_h
association [0..1] to I_BusinessUserBasic as _UserCreate on $projection.LocalCreatedBy = _UserCreate.UserID association [0..1] to I_BusinessUserBasic as _UserChange on $projection.LocalLastChangedBy = _UserChange.UserID association [0..1] to I_CompanyCode as _Company on $projection.CompanyCode = _Company.CompanyCode association [0..1] to I_Supplier as _Supplier on $projection.Supplier = _Supplier.Supplier // association [0..1] to I_PurchasingDocumentType as _PurchasingDocumentType on _PurchasingDocumentType.PurchasingDocumentCategory = 'F' //purchase order // and $projection.PurchaseOrderType2 = _PurchasingDocumentType.PurchasingDocumentType
association [0..1] to I_PurchasingOrganization as _PurchasingOrganization on $projection.PurchaseOrganization = _PurchasingOrganization.PurchasingOrganization
association [0..1] to I_PurchasingGroup as _PurchasingGroup on $projection.PurchaseGroup = _PurchasingGroup.PurchasingGroup
association [0..1] to I_PaymentTerms as _PaymentTerms on $projection.PaymentTerms = _PaymentTerms.PaymentTerms
association to parent ZEXED_I_UP_PDCMP as _File on $projection.ParentUUID = _File.UUID
composition [0..*] of ZEXED_I_UP_PDCMP_I as _Itens { key uuid as UUID, parent_uuid as ParentUUID, status as Status, case status when 'Erro' then 1 when 'Não publicado' then 2 when 'Publicado' then 3 else 0 end as CriticalityStatus, purchase_order as PurchaseOrder, concat_with_space('Pedido:',ltrim( purchase_order, '0' ),1) as LabelPurchaseOrder, purchase_order_type as PurchaseOrderType2, purchase_order_date as PurchaseOrderDate, company_code as CompanyCode, purchase_org as PurchaseOrganization, purchase_grp as PurchaseGroup, supplier as Supplier, payment_terms as PaymentTerms, _Company.CompanyCodeName as CompanyName, _Supplier.BPSupplierFullName as SupplierName, _PurchasingOrganization.PurchasingOrganizationName as PurchaseOrganizationName, _PurchasingGroup.PurchasingGroupName as PurchaseGroupName, @Semantics.user.createdBy: true local_created_by as LocalCreatedBy,
_UserCreate.PersonFullName as NameUserCreate,
@Semantics.systemDateTime.createdAt: true local_created_at as LocalCreatedAt,
@Semantics.user.lastChangedBy: true local_last_changed_by as LocalLastChangedBy,
_UserChange.PersonFullName as NameUserChange,
@Semantics.systemDateTime.localInstanceLastChangedAt: true local_last_changed_at as LocalLastChangedAt,
